import React, { Fragment } from 'react'
import { css } from '@linaria/core'
import { colors } from '@fs/zion-ui'

const matchingTextCss = css`
  color: ${colors.yellow50};
`
export function removeDiacritics(str) {
  // normalize() converts a string into unicode, from which we can replace a range of diacritic characters
  // https://stackoverflow.com/questions/990904/remove-accents-diacritics-in-a-string-in-javascript
  // https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/String/normalize
  return str.normalize('NFD').replace(/[\u0300-\u036f]/g, '')
}

function findCommon(str1 = '', str2 = '') {
  const s1 = [...str1.toLowerCase()]
  const s2 = [...str2.toLowerCase()]
  const arr = Array(s2.length + 1)
    .fill(null)
    .map(() => {
      return Array(s1.length + 1).fill(null)
    })
  for (let j = 0; j <= s1.length; j += 1) {
    arr[0][j] = 0
  }
  for (let i = 0; i <= s2.length; i += 1) {
    arr[i][0] = 0
  }
  let len = 0
  let col = 0
  let row = 0
  for (let i = 1; i <= s2.length; i += 1) {
    for (let j = 1; j <= s1.length; j += 1) {
      if (s1[j - 1] === s2[i - 1]) {
        arr[i][j] = arr[i - 1][j - 1] + 1
      } else {
        arr[i][j] = 0
      }
      if (arr[i][j] > len) {
        len = arr[i][j]
        col = j
        row = i
      }
    }
  }
  if (len === 0) {
    return ''
  }
  let res = ''
  while (arr[row][col] > 0) {
    res = s1[col - 1] + res
    row -= 1
    col -= 1
  }
  return res
}

export default function HighlightMatchingText({ children, textToHighlight, ignoreDiacritics }) {
  const inputText = ignoreDiacritics ? removeDiacritics(textToHighlight) : textToHighlight
  const testingStr = ignoreDiacritics ? removeDiacritics(children) : children
  const matchingText = findCommon(inputText, testingStr)

  if (matchingText?.length > 4) {
    const indexOfMatch = testingStr.toLowerCase().indexOf(matchingText)
    const charsToHighlight = children.substr(indexOfMatch, matchingText.length)
    const displayTermParts = children.split(charsToHighlight)

    return displayTermParts.map((textChunk, i) => {
      if (i === 0) {
        return textChunk
      }
      return (
        <Fragment key={textChunk + String(i)}>
          <span className={matchingTextCss}>{charsToHighlight}</span>
          {textChunk}
        </Fragment>
      )
    })
  }
  return children
}
